<template>
    <div class="confirm">
      <div class="nav">确认订单</div>
      <div class="content">
      <!-- 地址 -->
      <div class="address">
          <img src="../assets/line.jpg" alt="">
        <p class="big"><label>默认</label>{{address}}</p>
        <p>{{data.addressInfo.detail}}</p>
        <p>{{data.addressInfo.real_name}} {{data.addressInfo.phone}}</p>
      </div>
      <!-- 产品信息 -->
      <div class="product" v-for="(c,i) in product" :key="i">
           <img :src="c.productInfo.image" alt="">      
       <div class="msg">
           <div class="line1">
              {{c.productInfo.store_name}}
           </div>
           <div class="line2">
               <p> {{c.productInfo.attrInfo.suk}}</p>
              <span>* {{c.cart_num}}</span>
           </div>
           <div class="line3">￥{{c.productInfo.give_integral}}</div>
       </div>

      </div>
       <!-- 栏 -->
       <div class="other">
           <p>
               <span>优惠券</span>
               <span>请选择</span>
           </p>
           <p>
               <span>会员优惠</span>
               <span>-￥{{data.priceGroup.vipPrice}}</span>
           </p>

       </div>
       <!-- 支付方式 -->
       <div class="pay">
           <p>
               <span>余额支付</span>
               <span>余额 : {{data.userInfo.now_money}}</span>
           </p>
       </div>
       <!-- 总价 -->
       <div class="total">
          <p>
               <span>商品金额</span>
               <span>￥{{price.total_price}}</span>
           </p> 
            <p>
               <span>运费</span>
               <span>￥{{price.pay_postage}}</span>
           </p> 
            <p>
               <span>支付</span>
               <span>￥{{price.pay_price}}</span>
           </p> 
         
       </div>
       </div>
       <!-- 提交订单 -->
       <van-submit-bar :price='(price.pay_price)*100' button-text="提交订单" @submit="onSubmit" />
       
    </div>
</template>
<script>
export default {
  data() {
    return {
      data: "",
      address: "",
      product: [],
      num:'',
      price:''
    };
  },
  created() {
    console.log("订单详情=》", this.$route.query.cId);
    this.axios
      .post("/api/order/confirm", {
        cartId: this.$route.query.cId,
      })
      .then((d) => {
        this.data = d.data.data;
        this.address = d.data.data.addressInfo.province +" " +d.data.data.addressInfo.city + " " +d.data.data.addressInfo.district;
        this.product = d.data.data.cartInfo;
        console.log(this.data);

        this.axios.post('/api/order/computed/'+this.data.orderKey,{
            addressId: this.data.addressInfo.id,
            couponId: 0,
            payType: "yue",
            shipping_type: 1,
            useIntegral: 0
        }).then(data=>{

         this.price = data.data.data.result;
        //  console.log("价格汇总",this.price);
        })
      });
  },
  methods:{
     onSubmit(){
      this.axios.post('/api/order/create/'+this.data.orderKey,{
            addressId: 3353,//this.address.id
            bargainId: 0,
            combinationId: 0,
            couponId: 0,
            from: "weixinh5",
            mark: "",
            payType: "yue",
            phone: "",
            pinkId: 0,
            real_name: "",
            seckill_id: 0,
            shipping_type: 1,
            store_id: 0,
            useIntegral: 0
      }).then(d=>{
          this.num = d.data.data.result.orderId;
         this.$router.push({
               name:"PaySuccess",
                query: {num:this.num},
              });
        
      })   
     } 
  }
};
</script>

<style lang="less" scoped>
.confirm{
    margin-bottom: 50px;
    font-size: 16px;
    background-color: rgb(248, 247, 247);
    .nav{
      line-height: 40px;
      width:100%;
      position: sticky;
      top: 0;
      background-color: #fff;
      text-align: center;

  }
    .content{
    padding: 0 10px;  
  .address{
      height: 130px;
      background-color: #fff;
      margin: 10px auto;
      padding: 0 10px;
      p{
          line-height: 1;
      }
      p.big{
          font-weight: bold;
          font-size: 17px;
      label{
          color: #fff;
          font-size: 12px;
          padding: 2px;
          border-radius: 3px;
          background-color: #FA877B;
          margin-right: 10px;
      }
      }
      img{
          width: 100%;
      }
  }
  .product{
     display: flex;
     justify-content: space-around;
     background-color: #fff;
     padding: 5px;
     img{
         width: 25%;
         height: auto;
     }
     .msg{
         width: 70%;
         .line1{
             overflow: hidden;
             text-overflow:ellipsis ;
             white-space: nowrap;
         }
         .line2{
             display: flex;
             justify-content: space-between;
             align-items: center;
             color: #666;
             font-size: 14px;
         }
         .line3{
             color: #FA877B;
         }
     }
  }
 .other, .pay,.total{
     padding: 5px 10px;
     margin: 10px auto;
     border-radius: 10px;
     background-color: #fff;
      p{
      display: flex;
      justify-content: space-between;
      align-items: center;
      line-height: 30px;
      span{
          &:nth-child(2){
              color: #888;
              font-size: 14px;
          }
      }
      }   
  }
 }

}
</style>